import React from 'react';
// Eliminamos todas las importaciones de hooks y router

const SearchBox = () => {
  // Eliminamos toda la lógica de estado y efectos
  
  // CLASES CRÍTICAS DE TAILWIND PARA EL DISEÑO:
  // 1. relative flex items-center w-full: Para posicionar la lupa dentro del input.
  // 2. rounded-full: Para el diseño de pastilla completa.
  // 3. bg-white: Fondo blanco.
  // 4. pl-10 pr-4: Padding para dejar espacio al icono y al final.

  return (
    <div className="relative flex items-center w-full max-w-sm" role="search">
      {/* 1. Ícono de búsqueda posicionado a la izquierda (gris suave) */}
      <i className="fas fa-search absolute left-3 text-gray-400"></i>
      
      {/* 2. Campo de Input Estático */}
      <input
        type="text"
        name="q"
        placeholder="Buscar productos..."
        // Clases para el diseño de pastilla
        className="w-full h-10 py-0 pl-10 pr-4 rounded-full border-0 shadow-sm 
          bg-white text-gray-900 placeholder-gray-500 focus:outline-none 
          focus:ring-2 focus:ring-[var(--cta-color)] focus:border-transparent 
          transition-all duration-200"
        aria-label="Buscar productos"
        // Valores estáticos
        defaultValue="" 
        readOnly 
      />
      
      {/* Eliminamos el spinner y el botón de limpiar para dejarlo 100% estático */}
      
    </div>
  );
};

export default SearchBox;
